# 4. 出生日時吉利方位（第41-42頁完整表格）
# ──────────────────────────────────────────────────────────────

WEEKDAY_DIRECTIONS: Dict[str, List[str]] = {
    "Sunday":    ["北方", "西北方"],
    "Monday":    ["東南方", "西南方"],
    "Tuesday":   ["東方", "東南方"],
    "Wednesday": ["北方", "西北方"],
    "Thursday":  ["東南方", "西南方"],
    "Friday":    ["西方", "西北方"],
    "Saturday":  ["東方", "東南方"],
}

# 時辰方位（印度傳統時辰）
TIME_DIRECTIONS: Dict[str, List[str]] = {
    "5-7":   ["東方", "東南方"],    # 卯時
    "7-9":   ["北方", "西北方"],    # 辰時
    "9-11":  ["東南方", "西南方"],  # 巳時
    "11-13": ["西方", "西北方"],    # 午時
    "13-15": ["東方", "東南方"],    # 未時
    "15-17": ["北方", "西北方"],    # 申時
    "17-19": ["東南方", "西南方"],  # 酉時
    "19-21": ["西方", "西北方"],    # 戌時
    "21-23": ["東方", "東南方"],    # 亥時
    "23-1":  ["北方", "西北方"],    # 子時
    "1-3":   ["東南方", "西南方"],  # 丑時
    "3-5":   ["西方", "西北方"],    # 寅時
}


def get_auspicious_direction(weekday: str, birth_hour: int) -> Tuple[str, str]:
    """返回出生星期 + 出生時辰的最吉方位（1952年版第41-42頁）。

    Args:
        weekday: 英文星期名稱，例如 "Sunday"。
        birth_hour: 24小時制出生時辰（0-23）。

    Returns:
        (星期最吉方位, 時辰最吉方位) 字串元組。
    """
    day_dirs = WEEKDAY_DIRECTIONS.get(weekday, ["東方", "東南方"])

    # 找到對應時辰區間
    hour_dir_key = "11-13"  # 預設午時
    for slot in TIME_DIRECTIONS:
        parts = slot.split("-")
        start = int(parts[0])
        end = int(parts[1])
        if start < end:
            if start <= birth_hour < end:
                hour_dir_key = slot
                break
        else:  # 跨午夜 (23-1)
            if birth_hour >= start or birth_hour < end:
                hour_dir_key = slot
                break

    hour_dirs = TIME_DIRECTIONS.get(hour_dir_key, ["東方", "東南方"])
    return day_dirs[0], hour_dirs[0]


