# 5. 三十五年週期（35-Year Cycle）完整計算模組（第38-40頁）
# ──────────────────────────────────────────────────────────────

# 各行星主運年數（Lal Kitab 35年制）
PLANET_DASHA_YEARS: Dict[str, int] = {
    "Saturn":  6,
    "Sun":     2,
    "Moon":    1,
    "Mars":    3,
    "Jupiter": 6,
    "Venus":   2,
    "Mercury": 6,
    "Rahu":    6,
    "Ketu":    3,
}

# 吉祥宮位（行星在此宮位時主運佳）
_AUSPICIOUS_HOUSES = {1, 4, 5, 9, 10, 11}


def calculate_35_year_cycle(
    birth_date: datetime.date,
    planets_in_house: Dict[str, int],
) -> Dict[str, Any]:
    """計算1952年版獨有「三十五年週期」。

    Args:
        birth_date: 出生日期。
        planets_in_house: 行星→宮位映射，例如 {"Sun": 10, "Moon": 4}。

    Returns:
        字典，鍵為年齡區間字符串，值含行星名、年數、宮位、狀態、補救建議。
    """
    cycle: Dict[str, Any] = {}
    age = 0
    for i in range(3):  # 計算三個連續的35年週期（每週期9顆行星，合計105年）
        for planet, years in PLANET_DASHA_YEARS.items():
            house = planets_in_house.get(planet, 1)
            status = (
                "成果豐盛" if house in _AUSPICIOUS_HOUSES
                else "需補救（貧困狀態）"
            )
            key = f"週期{i+1} 年齡{age}-{age + years}"
            cycle[key] = {
                "planet": planet,
                "planet_zh": PLANETS_ZH.get(planet, planet),
                "years": years,
                "house": house,
                "status": status,
                "remedy": (
                    f"捐贈{PLANETS_ZH.get(planet, planet)}對應顏色物品"
                    f"（建議顏色：{HOUSE_COLOR_RULES.get(house, {}).get('recommended', '見表')}）"
                ),
            }
            age += years
    return cycle


# ──────────────────────────────────────────────────────────────
# 6. 盲星 / 半盲星 / 清醒星判斷（1952年版特色）
# ──────────────────────────────────────────────────────────────

_ANGULAR_HOUSES = {1, 4, 7, 10}


def is_blind_planet(planet: str, house: int, lagna: int = 1) -> str:
    """1952年版盲星判定。

    Returns:
        描述字串：「盲星（極強影響）」、「半盲星（力量減半）」或「清醒星（正常發揮）」。
    """
    if planet in ("Rahu", "Ketu"):
        return "盲星（極強影響）"
    if (
        (planet == "Saturn" and house in _ANGULAR_HOUSES)
        or (planet == "Mars" and house in _ANGULAR_HOUSES)
    ):
        return "半盲星（力量減半）"
    return "清醒星（正常發揮）"


