def get_complete_remedies(planets_in_house: Dict[str, int]) -> Dict[str, Any]:
    """一次性取得所有補救措施。

    Args:
        planets_in_house: 行星→宮位映射，例如 {"Sun": 10, "Moon": 4}。

    Returns:
        包含通用補救及各行星補救的字典。
    """
    result: Dict[str, Any] = {"general": GENERAL_REMEDIES}
    for planet, house in planets_in_house.items():
        result[planet] = {
            "house": house,
            "specific_remedies": get_remedies(planet, house),
            "house_color": get_house_color_remedy(house),
        }
    return result


