def get_full_lal_kitab_analysis(
    planets_in_house: Dict[str, int],
    birth_weekday: str,
    birth_hour: int,
    birth_date: Optional[datetime.date] = None,
) -> Dict[str, Any]:
    """單一呼叫取得1952年版完整分析。

    Args:
        planets_in_house: 行星→宮位映射。
        birth_weekday: 英文星期名稱，例如 "Sunday"。
        birth_hour: 24小時制出生時辰（0-23）。
        birth_date: 出生日期（用於35年週期計算），預設使用今日。

    Returns:
        包含宮位解釋、盲星狀態、房屋顏色、吉方位及35年週期的完整字典。
    """
    if birth_date is None:
        birth_date = datetime.date.today()

    analysis: Dict[str, Any] = {}
    for planet, house in planets_in_house.items():
        analysis[planet] = {
            "house_interpretation": (
                PLANET_IN_HOUSE_FULL.get(planet, {}).get(house, "待補充")
            ),
            "blind_status": is_blind_planet(planet, house),
            "house_color": HOUSE_COLOR_RULES.get(house, {}),
        }
    analysis["auspicious_direction"] = get_auspicious_direction(
        birth_weekday, birth_hour
    )
    analysis["35_year_cycle"] = calculate_35_year_cycle(
        birth_date, planets_in_house
    )
    return analysis


