class PalmistryLongevityCalculator:
    """Lal Kitab 1952 手相壽命計算器。

    輸入生命線長度描述、心臟線/智慧線交叉位置、主要掌紋特徵，
    輸出預估壽命、死亡徵兆及警告。
    """

    # 生命線長度對應壽命（第1165頁）
    LIFE_LINE_AGES: Dict[str, int] = {
        "10歲位置":   10,
        "12歲位置":   12,
        "21歲位置":   21,
        "90歲位置":   90,
        "生命線末端": 100,
        "太陽線末端": 120,
    }

    # 心臟線交叉年齡（第1166頁）
    HEART_LINE_CROSSINGS: Dict[int, str] = {
        35: "農業線與心臟線交叉 → 35歲重大轉折",
        45: "生命線與心臟線交叉 → 45歲健康危機",
        56: "農業線與心臟線交叉 → 56歲後期注意",
    }

    # 掌紋數量壽命表（第1161頁）
    LINE_COUNT_LONGEVITY: Dict[int, int] = {
        1: 30,
        2: 60,
        3: 90,
        4: 120,
    }

    # 死亡徵兆（第1166-1167頁）
    DEATH_WARNINGS: Dict[str, str] = {
        "Y字分叉生命線":             "意外或中毒死亡風險",
        "火星丘延伸太陽丘":           "意外或中毒死亡",
        "水星丘線與生命線相交":       "疾病死亡",
        "太陽丘線斷裂":               "非自然死亡",
        "心臟線與頭髮線相交形成三角形": "災難死亡",
        "事業線斜向生命線":           "死於他人之手",
        "感情線與智慧線相交延伸手掌外側": "心臟病或中風",
    }

    @staticmethod
    def calculate_longevity(
        life_line_desc: str = "生命線末端",
        heart_line_cross_year: Optional[int] = None,
        head_line_cross_year: Optional[int] = None,
        total_major_lines: int = 3,
        special_warnings: Optional[List[str]] = None,
    ) -> Dict[str, Any]:
        """計算預估壽命與警告。

        Args:
            life_line_desc: 生命線描述，例如 "90歲位置"、"生命線末端"。
            heart_line_cross_year: 心臟線交叉年齡（35/45/56）。
            head_line_cross_year: 智慧線交叉年齡（目前保留供未來擴充）。
            total_major_lines: 主要掌紋數量（1-4）。
            special_warnings: 特殊死亡徵兆描述列表。

        Returns:
            包含預估壽命、警告及補救建議的字典。
        """
        base_longevity = PalmistryLongevityCalculator.LIFE_LINE_AGES.get(
            life_line_desc, 75
        )
        line_bonus = PalmistryLongevityCalculator.LINE_COUNT_LONGEVITY.get(
            total_major_lines, 75
        )

        # 最終壽命 = 生命線基礎 + 掌紋數量加成（取平均）
        estimated_age = (base_longevity + line_bonus) // 2

        warnings: List[str] = []
        if heart_line_cross_year in PalmistryLongevityCalculator.HEART_LINE_CROSSINGS:
            warnings.append(
                PalmistryLongevityCalculator.HEART_LINE_CROSSINGS[heart_line_cross_year]
            )

        if special_warnings:
            for w in special_warnings:
                if w in PalmistryLongevityCalculator.DEATH_WARNINGS:
                    warnings.append(PalmistryLongevityCalculator.DEATH_WARNINGS[w])

        return {
            "estimated_longevity": f"{estimated_age}歲左右",
            "base_life_line": life_line_desc,
            "heart_line_warning": warnings,
            "remedy_suggestion": (
                "生命線短或有斷裂 → 立即進行太陽/火星補救（捐紅色物品、餵狗）"
            ),
            "confidence": "高" if estimated_age > 80 else "中",
        }


