class FarmanRuleEngine:
    """Lal Kitab 1952 Farman 規則引擎。

    根據宮位、行星、房屋狀態自動匹配對應 Farman 規則。
    """

    @staticmethod
    def get_farman_advice(
        house: Optional[int] = None,
        planet: Optional[str] = None,
        condition: Optional[str] = None,
    ) -> Dict[str, Any]:
        """查詢特定 Farman 規則。

        Args:
            house: 宮位數字（可選）。
            planet: 行星英文名稱（可選）。
            condition: 查詢條件關鍵字（可選）。

        Returns:
            包含匹配 Farman 建議的字典。
        """
        results = []
        for fnum, rule in FARMAN_RULES.items():
            matched = False
            if house is not None and str(house) in rule.get("note", ""):
                matched = True
            if planet is not None and planet in rule.get("note", ""):
                matched = True
            if condition is not None and condition.lower() in rule.get("condition", "").lower():
                matched = True
            # Note: substring matching is intentional to allow flexible keyword queries
            if matched:
                results.append({
                    "farman_number": fnum,
                    "rule": rule["rule"],
                    "remedy": rule["remedy"],
                    "note": rule["note"],
                })
        return {
            "matched_farmans": results or [
                {
                    "farman_number": "通用",
                    "rule": "參考GENERAL_REMEDIES",
                    "remedy": GENERAL_REMEDIES,
                }
            ],
            "total_matches": len(results),
        }

    @staticmethod
    def get_all_house_farmans(
        planets_in_house: Dict[str, int],
    ) -> Dict[str, Any]:
        """一次取得所有房屋對應 Farman 建議。

        Args:
            planets_in_house: 行星→宮位映射。

        Returns:
            各行星 Farman 建議字典。
        """
        advice: Dict[str, Any] = {}
        for planet, house in planets_in_house.items():
            advice[planet] = FarmanRuleEngine.get_farman_advice(
                house=house, planet=planet
            )
        return advice


