def get_palmistry_and_farman_analysis(
    planets_in_house: Dict[str, int],
    life_line_desc: str = "生命線末端",
    heart_line_cross_year: Optional[int] = None,
    total_major_lines: int = 3,
) -> Dict[str, Any]:
    """一次性取得手相壽命 + Farman 規則完整分析。

    Args:
        planets_in_house: 行星→宮位映射。
        life_line_desc: 生命線描述。
        heart_line_cross_year: 心臟線交叉年齡。
        total_major_lines: 主要掌紋數量（1-4）。

    Returns:
        包含手相壽命分析、Farman 規則及整合補救的字典。
    """
    palm = PalmistryLongevityCalculator.calculate_longevity(
        life_line_desc=life_line_desc,
        heart_line_cross_year=heart_line_cross_year,
        total_major_lines=total_major_lines,
    )
    farman = FarmanRuleEngine.get_all_house_farmans(planets_in_house)
    return {
        "palmistry_longevity": palm,
        "farman_rules": farman,
        "combined_remedy": "結合 Palmistry 警告 + Farman 房屋顏色補救",
    }


